import{_ as i,o as n,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"04. Clinical Nurse Midwife Specialist Criteria","description":"","frontmatter":{"title":"04. Clinical Nurse Midwife Specialist Criteria","eba":"Nurses and Midwives 2024-2028","topics":["appendices","classifications"]},"headers":[],"relativePath":"ebas/nurses-midwives/appendices/04-clinical-nurse-midwife-specialist-criteria.md","filePath":"ebas/nurses-midwives/appendices/04-clinical-nurse-midwife-specialist-criteria.md"}'),t={name:"ebas/nurses-midwives/appendices/04-clinical-nurse-midwife-specialist-criteria.md"};function o(s,e,c,l,d,p){return n(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="_04-clinical-nurse-midwife-specialist-criteria" tabindex="-1">04. Clinical Nurse Midwife Specialist Criteria <a class="header-anchor" href="#_04-clinical-nurse-midwife-specialist-criteria" aria-label="Permalink to &quot;04. Clinical Nurse Midwife Specialist Criteria&quot;">​</a></h1><p>Formatting note</p><p>The appendix body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find appendices by their title, number, topic or synonyms.</p><p>\`\`\`text – CLINICAL NURSE/MIDWIFE SPECIALIST CRITERIA</p><p>Applicants must meet the clinical nurse/midwife specialist definition, be employed either full-time or part-time and demonstrate one criterion in each of paragraphs 1, 2 and 3. 1. Clinical Skill</p><pre><code>        •           Higher level of skill demonstrated in clinical decision making – in particular in
                    problem identification and solution, and analysis and interpretation of clinical data;
                    and

        •           Maintenance and improvement of clinical standards.
</code></pre><ol><li><p>Professional Behaviour</p><pre><code>    •           Positive role model;

    •           Act as a mentor or preceptor to less experienced nurses/midwives, including
                graduate nurses/midwives;

    •           Support of, and contribution to, quality improvement and research projects within
                the area of practice and ward/unit/department; and

    •           Act as a resource person to others in relation to clinical practice.
</code></pre></li><li><p>Professional Development</p><pre><code>    •           Membership of relevant professional body, and ability to demonstrate and
                document:

                (i)         learning from a journal article, or attendance at a conference or seminar,
                            or reflection on seminar or conference papers;

                (ii)        participation in effective learning activities relevant to their learning
                            needs; or

                (iii)       membership of a sub-grouping of the professional association relevant to
                            their area of practice;

    •           Contribution to the education of other professionals, for example, being willing to
                provide at least one in-service education program each year; and

    •           Undertaking own planned professional development and competence through
                various forms of continuing education, for example, conferences, study days, formal
                study, reading.
</code></pre></li></ol><p>Appendix 4 – Clinical Nurse/Midwife Specialist Criteria 246 \`\`\`</p>`,8)])])}const u=i(t,[["render",o]]);export{f as __pageData,u as default};
